int main() {
    int T, N, i, j, moves, max, min;
    int A[101];
    char input[1024];

    while (scanf("%d", &T) == 1) {
        while (T--) {
            scanf("%d", &N);
            scanf("%*s");
            for (i = 0; i < N; i++) {
                scanf("%d", &A[i]);
            }
            moves = 0;
            for (i = 0; i < N; i++) {
                max = A[i];
                min = A[i];
                for (j = i; j < N; j++) {
                    max = std::max(max, A[j]);
                    min = std::min(min, A[j]);
                }
                moves += std::min(std::min(i, N - i - 1), std::min(std::abs(A[i] - max), std::abs(A[i] - min)));
            }
            printf("%d\n", moves);
        }
    }
    return 0;
}

