code.Java:
public class Main {
    public static void main(String[] args) {
        java.util.Scanner scanner = new java.util.Scanner(System.in);
        int T, N, i, j, moves, max, min;
        int[] A = new int[101];

        while (scanner.hasNextInt()) {
            T = scanner.nextInt();
            while (T-- > 0) {
                N = scanner.nextInt();
                scanner.nextLine();
                for (i = 0; i < N; i++) {
                    A[i] = scanner.nextInt();
                }
                moves = 0;
                for (i = 0; i < N; i++) {
                    max = A[i];
                    min = A[i];
                    for (j = i; j < N; j++) {
                        max = Math.max(max, A[j]);
                        min = Math.min(min, A[j]);
                    }
                    moves += Math.min(Math.min(i, N - i - 1), Math.min(Math.abs(A[i] - max), Math.abs(A[i] - min)));
                }
                System.out.println(moves);
            }
        }
    }
}

