const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/
/);
let T = parseInt(input.shift());
let i = 0;

while (T--) {
    let N = parseInt(input[i++]);
    let A = input[i++].split(' ').map(Number);
    let moves = 0;

    for (let j = 0; j < N; j++) {
        let max_val = A[j];
        let min_val = A[j];

        for (let k = j; k < N; k++) {
            max_val = Math.max(max_val, A[k]);
            min_val = Math.min(min_val, A[k]);
        }

        moves += Math.min(Math.min(j, N - j - 1), Math.min(Math.abs(A[j] - max_val), Math.abs(A[j] - min_val)));
    }

    console.log(moves);
}
